import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { Search, Calendar, MapPin, Car, Users, Clock, ArrowRight } from 'lucide-react';
import VehicleCard from '@components/vehicles/VehicleCard';
import { useVehicles } from '@hooks/useVehicles';
import type { Vehicle } from '@types';

const Home: React.FC = () => {
  const navigate = useNavigate();
  const { vehicles, loading, fetchVehicles } = useVehicles();
  const [searchData, setSearchData] = useState({
    location: '',
    startDate: '',
    endDate: ''
  });

  useEffect(() => {
    fetchVehicles({ limit: 8 });
  }, []);

  const featuredVehicles = vehicles.slice(0, 6);

  const handleSearch = (e: React.FormEvent) => {
    e.preventDefault();
    const params = new URLSearchParams();
    if (searchData.location) params.append('location', searchData.location);
    if (searchData.startDate) params.append('startDate', searchData.startDate);
    if (searchData.endDate) params.append('endDate', searchData.endDate);
    navigate(`/vehicles?${params.toString()}`);
  };

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Hero Section */}
      <section className="relative bg-gradient-to-r from-blue-600 to-blue-800 text-white">
        <div className="absolute inset-0 opacity-10 bg-[url('/images/hero-bg.jpg')] bg-cover bg-center"></div>
        
        <div className="relative container mx-auto px-4 py-20 lg:py-28">
          <div className="max-w-3xl">
            <h1 className="text-4xl md:text-5xl lg:text-6xl font-bold mb-4 leading-tight">
              MOTO - Cùng Bạn Trên Mọi Hành Trình
            </h1>
            <p className="text-xl md:text-2xl mb-8 opacity-90">
              Trải nghiệm sự khác biệt từ 15.000 xe gia đình đời mới khắp Việt Nam
            </p>
            
            {/* Search Form */}
            <form onSubmit={handleSearch} className="bg-white rounded-2xl shadow-2xl p-4 md:p-6 text-gray-800">
              <div className="grid grid-cols-1 md:grid-cols-4 gap-3">
                <div className="relative">
                  <MapPin className="absolute left-3 top-3.5 text-blue-500" size={20} />
                  <input
                    type="text"
                    placeholder="Địa điểm"
                    value={searchData.location}
                    onChange={(e) => setSearchData({...searchData, location: e.target.value})}
                    className="w-full pl-10 pr-4 py-3 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
                  />
                </div>
                <div className="relative">
                  <Calendar className="absolute left-3 top-3.5 text-blue-500" size={20} />
                  <input
                    type="date"
                    value={searchData.startDate}
                    onChange={(e) => setSearchData({...searchData, startDate: e.target.value})}
                    className="w-full pl-10 pr-4 py-3 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
                  />
                </div>
                <div className="relative">
                  <Calendar className="absolute left-3 top-3.5 text-blue-500" size={20} />
                  <input
                    type="date"
                    value={searchData.endDate}
                    onChange={(e) => setSearchData({...searchData, endDate: e.target.value})}
                    className="w-full pl-10 pr-4 py-3 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
                  />
                </div>
                <button
                  type="submit"
                  className="bg-blue-600 text-white py-3 px-6 rounded-lg hover:bg-blue-700 transition flex items-center justify-center gap-2 font-medium"
                >
                  <Search size={20} />
                  Tìm Xe
                </button>
              </div>
            </form>
          </div>
        </div>
      </section>

      {/* Stats Section */}
      <section className="py-12 bg-white shadow-sm">
        <div className="container mx-auto px-4">
          <div className="grid grid-cols-2 md:grid-cols-4 gap-8">
            <div className="text-center">
              <div className="text-3xl md:text-4xl font-bold text-blue-600">15.000+</div>
              <div className="text-gray-600 mt-1">Xe đa dạng</div>
            </div>
            <div className="text-center">
              <div className="text-3xl md:text-4xl font-bold text-blue-600">500.000+</div>
              <div className="text-gray-600 mt-1">Khách hàng</div>
            </div>
            <div className="text-center">
              <div className="text-3xl md:text-4xl font-bold text-blue-600">4.8/5</div>
              <div className="text-gray-600 mt-1">Đánh giá</div>
            </div>
            <div className="text-center">
              <div className="text-3xl md:text-4xl font-bold text-blue-600">63</div>
              <div className="text-gray-600 mt-1">Tỉnh thành</div>
            </div>
          </div>
        </div>
      </section>

      {/* Service Features */}
      <section className="py-16 container mx-auto px-4">
        <h2 className="text-3xl font-bold text-center mb-12">Dịch vụ của chúng tôi</h2>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
          <div className="bg-white p-6 rounded-xl shadow-md text-center hover:shadow-lg transition">
            <div className="w-16 h-16 bg-blue-100 rounded-full flex items-center justify-center mx-auto mb-4">
              <Car className="text-blue-600" size={32} />
            </div>
            <h3 className="text-xl font-semibold mb-2">Xe tự lái</h3>
            <p className="text-gray-600">Thuê xe tự lái với đa dạng mẫu mã, giá cả hợp lý</p>
          </div>
          <div className="bg-white p-6 rounded-xl shadow-md text-center hover:shadow-lg transition">
            <div className="w-16 h-16 bg-blue-100 rounded-full flex items-center justify-center mx-auto mb-4">
              <Users className="text-blue-600" size={32} />
            </div>
            <h3 className="text-xl font-semibold mb-2">Xe có tài xế</h3>
            <p className="text-gray-600">Dịch vụ xe có tài xế chuyên nghiệp, an toàn</p>
          </div>
          <div className="bg-white p-6 rounded-xl shadow-md text-center hover:shadow-lg transition">
            <div className="w-16 h-16 bg-blue-100 rounded-full flex items-center justify-center mx-auto mb-4">
              <Clock className="text-blue-600" size={32} />
            </div>
            <h3 className="text-xl font-semibold mb-2">Thuê xe dài hạn</h3>
            <p className="text-gray-600">Gói thuê xe dài hạn với nhiều ưu đãi hấp dẫn</p>
          </div>
        </div>
      </section>

      {/* Featured Vehicles */}
      <section className="py-16 bg-gray-50">
        <div className="container mx-auto px-4">
          <div className="flex justify-between items-center mb-8">
            <div>
              <h2 className="text-3xl font-bold">Xe nổi bật</h2>
              <p className="text-gray-500 mt-1">Những chiếc xe được quan tâm nhiều nhất</p>
            </div>
            <Link to="/vehicles" className="text-blue-600 hover:text-blue-700 font-semibold flex items-center gap-1">
              Xem tất cả
              <ArrowRight size={18} />
            </Link>
          </div>
          
          {loading ? (
            <div className="text-center py-12">
              <div className="spinner h-12 w-12 border-4 border-blue-500 border-t-transparent rounded-full"></div>
            </div>
          ) : (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
              {featuredVehicles.map((vehicle: Vehicle) => (
                <VehicleCard key={vehicle.id} vehicle={vehicle} />
              ))}
            </div>
          )}
        </div>
      </section>

      {/* About MOTO */}
      <section className="py-16 container mx-auto px-4">
        <div className="max-w-4xl mx-auto text-center">
          <h2 className="text-3xl font-bold mb-6">Về MOTO</h2>
          <div className="space-y-4 text-gray-600 text-lg leading-relaxed">
            <p>
              <strong className="text-blue-600">MOTO</strong> là nền tảng chia sẻ ô tô, sứ mệnh của chúng tôi không chỉ dừng lại ở việc 
              kết nối chủ xe và khách hàng một cách <strong className="text-blue-600">Nhanh chóng - An toàn - Tiện lợi</strong>, 
              mà còn hướng đến việc truyền cảm hứng <strong className="text-blue-600">KHÁM PHÁ</strong> những điều mới mẻ 
              đến cộng đồng qua những chuyến đi trên nền tảng của chúng tôi.
            </p>
            <p>
              MOTO - Chuyến đi là một hành trình khám phá cuộc sống và thế giới xung quanh, 
              là cơ hội học hỏi và chinh phục những điều mới mẻ.
            </p>
          </div>
        </div>
      </section>
    </div>
  );
};

export default Home;